const WHITELIST=["api.whatsapp.com"];function verifyIfIsAbleToModify(t){for(const e of WHITELIST)if(t.includes(e))return!1;return!0}function persistParams(){const t=window.location.search||"",e=document.getElementsByTagName("a");Array.from(e).forEach((e=>{if(verifyIfIsAbleToModify(e.href)&&e.href){const o=e.href,n=t.startsWith("&")?t.replace("&",""):t.replace("?","");!o.includes("https://")&&!o.includes("http://")||o.includes("#")||e.setAttribute("href",`${o}${n?o.includes("?")?`&${n}`:`?${n}`:""}`)}}));var o=window.location.protocol+"//"+window.location.host+window.location.pathname+t;window.history.pushState({path:o},"",o)}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",persistParams):persistParams();